import dpkt, socket
from collections import defaultdict
pcap='/home/ctfplayer/ctf_files/cap.pcap'
conns=defaultdict(list)
for ts,buf in dpkt.pcap.Reader(open(pcap,'rb')):
    try:
        eth=dpkt.ethernet.Ethernet(buf); ip=eth.data; tcp=ip.data
        if isinstance(ip, dpkt.ip.IP) and isinstance(tcp, dpkt.tcp.TCP) and tcp.dport==8080 and tcp.data:
            key=(socket.inet_ntoa(ip.src),tcp.sport,socket.inet_ntoa(ip.dst),tcp.dport)
            conns[key].append((tcp.seq, bytes(tcp.data)))
    except: pass

def reassemble(segs):
    segs=sorted(segs)
    out=[]; cur=None
    for seq,data in segs:
        if cur is None:
            out.append((seq,data)); cur=seq+len(data); continue
        if seq>cur:
            out.append((seq,data)); cur=seq+len(data)
        else:
            ov=cur-seq
            if ov < len(data):
                out.append((cur,data[ov:])); cur=seq+len(data)
    return b''.join(d for _,d in out)
for key,segs in conns.items():
    data=reassemble(segs)
    if b'x=' in data:
        print('found in conn',key)
        idx=data.find(b'x=')
        print(data[max(0,idx-200):idx+500])
        break
else:
    print('no x in reassembled conns')
